import Header from './Header';
import Content from './Content';
import Footer from './Footer';
import Additems from './Additems';
import SearchItem from './SearchItem';
import { useEffect, useState } from 'react';
import apiRequest from './apiRequest';

function App() {
  const [items, setItems] = useState([]);
  const [newItem, setNewItem] = useState('');
  const [search, setSearch] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const API_URL = 'http://localhost:3500/items';

  // Fetch data from the local host server
  useEffect(() => {
    const fetchItems = async () => {
      try {
        const response = await fetch(API_URL);
        if (!response.ok) {
          throw new Error('Error fetching items');
        }
        const listItems = await response.json();
        setItems(listItems);
      } catch (error) {
        setErrorMsg(error.message);
      } finally {
        setIsLoading(false);
      }
    };

    setTimeout(() => {
      fetchItems();
    }, 500); // Changed delay to 500ms for smoother loading
  }, []);

  const changeCheckList = async (id) => {
    const updatedItems = items.map((item) =>
      item.id === id ? { ...item, checked: !item.checked } : item
    );
    setItems(updatedItems);

    const myItems = updatedItems.find((item) => item.id === id);

    const updateOptions = {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ checked: myItems.checked }),
    };

    const updateUrl = `${API_URL}/${id}`;
    const result = await apiRequest(updateUrl, updateOptions);

    if (result) {
      setErrorMsg(result);
    }
  };

  const changeDelete = async (id) => {
    const updatedItems = items.filter((item) => item.id !== id);
    setItems(updatedItems);

    const deleteOption = {
      method: 'DELETE',
    };

    const updateUrl = `${API_URL}/${id}`;
    const result = await apiRequest(updateUrl, deleteOption);

    if (result) {
      setErrorMsg(result);
    }
  };

  const addItem = async (activity) => {
    const newId = items.length ? items[items.length - 1].id + 1 : 1;
    const newItem = { id: newId, activity, checked: false };

    setItems([...items, newItem]);

    const postOptions = {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newItem),
    };

    const result = await apiRequest(API_URL, postOptions);

    if (result) {
      setErrorMsg(result);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!newItem.trim()) {
      return;
    }

    addItem(newItem.trim());
    setNewItem('');
  };

  return (
    <div className="div">
      <Header title="To-Do Lists" />
      <SearchItem search={search} setSearch={setSearch} />
      <Additems newItem={newItem} setNewItem={setNewItem} handleSubmit={handleSubmit} />
      <main>
        {isLoading && <p>Items Loading...</p>}
        {errorMsg && <p>Error: {errorMsg}</p>}
        {!isLoading && !errorMsg && (
          <Content
            items={items.filter((item) =>
              item.activity.toLowerCase().includes(search.toLowerCase())
            )}
            handleChange={changeCheckList}
            changeDelete={changeDelete}
          />
        )}
      </main>
      <Footer items={items} />
    </div>
  );
}

export default App;
